const modelo = ($input.first().json.modelo || '').trim();
const tipo = ($input.first().json.tipo || 'exterior').toLowerCase();
const telefono = $input.first().json.telefono;

const BASE = 'https://agncorp.com.ar/marcaschinas';

const MAPA = {
  'JAC JS2':                 { exterior: `${BASE}/jac/jac-s2/jac-s2.jpg`, interior: `${BASE}/jac/jac-s2/jac-s2-tablero.jpg` },
  'JAC JS4':                 { exterior: `${BASE}/jac/jac-js4-flagship/jac-js4.jpg` },
  'JAC JS4 Flagship':        { exterior: `${BASE}/jac/jac-js4-flagship/jac-js4.jpg` },
  'JAC JS4 Luxury':          { exterior: `${BASE}/jac/jac-js4-luxury/jac-js4.jpg` },
  'JAC JS6 PHEV':            { exterior: `${BASE}/jac/jac-js6-phev/jac-js6-phev.jpg` },
  'JAC JS8':                 { exterior: `${BASE}/jac/jac-js8-pro/jac-js8-pro.jpg` },
  'JAC JS8 Pro':             { exterior: `${BASE}/jac/jac-js8-pro/jac-js8-pro.jpg` },
  'JAC EV30X':               { exterior: `${BASE}/jac/ev-30x/jac-ev-30x.jpg` },
  'JAC T8':                  { exterior: `${BASE}/jac/jac-t8-intelligent/jac-t8-intelligent.jpg` },
  'JAC T8 Intelligent':      { exterior: `${BASE}/jac/jac-t8-intelligent/jac-t8-intelligent.jpg` },
  'JAC T9':                  { exterior: `${BASE}/jac/jac-t9/jac-t9.jpg` },
  'Chery Tiggo 4 Pro':       { exterior: `${BASE}/chery/chery-tiggo-4-pro-luxury/chery-tiggo-4-pro-luxury.jpg` },
  'Chery Tiggo 4 Pro Luxury':{ exterior: `${BASE}/chery/chery-tiggo-4-pro-luxury/chery-tiggo-4-pro-luxury.jpg` },
  'GAC GS3':                 { exterior: `${BASE}/gac/gs3-emzoom/gac-gs3-emzoom.jpg` },
  'GAC GS3 EMZOOM':          { exterior: `${BASE}/gac/gs3-emzoom/gac-gs3-emzoom.jpg` },
  'GAC EMKOO':               { exterior: `${BASE}/gac/emkoo/gac-emkoo.jpg` },
  'GAC GS8':                 { exterior: `${BASE}/gac/gs8/gs8.jpg` },
  'GAC EMPOWER':             { exterior: `${BASE}/gac/nuevo-empow/empow.jpg` },
  'GAC NUEVO EMPOW':         { exterior: `${BASE}/gac/nuevo-empow/empow.jpg` },
  'GAC AION ES':             { exterior: `${BASE}/gac/aion-es/aion-es.jpg` }
};

const entry = MAPA[modelo];

if (!entry) {
  return [{ json: {
    success: false,
    error: `No tengo imagen registrada para "${modelo}". Modelos disponibles: ${Object.keys(MAPA).join(', ')}`,
    modelo,
    tipo,
    telefono
  }}];
}

const link = entry[tipo];

if (!link) {
  const mensajeError = tipo === 'interior'
    ? `No tengo imagen interior del ${modelo}. Solo cuento con imagen exterior.`
    : `No tengo imagen ${tipo} del ${modelo}.`;

  return [{ json: {
    success: false,
    error: mensajeError,
    modelo,
    tipo,
    telefono
  }}];
}

return [{ json: { telefono, modelo, link, tipo, success: true }}];
